};
function flag(n) { return FLAGS[n] || '⚽'; }

const lineups  = lineupResp.response || [];
const posOrder = {G:1, D:2, M:3, F:4};
const nameMap  = {};

for (const team of lineups) {
  const all = [...(team.startXI||[]).map(p=>p.player), ...(team.substitutes||[]).map(p=>p.player)];
  for (const player of all) {
    const full = player?.name;
    if (!full) continue;
    nameMap[full] = full;
    const parts = full.trim().split(/\s+/);
    if (parts.length >= 2) {
      const abbrev = parts[0].charAt(0).toUpperCase() + '. ' + parts.slice(1).join(' ');
      nameMap[abbrev] = full;
    }
  }
}
globalSd[`nm_${orig.partido_id}`] = nameMap;

function fmtTeam(t) {
  const f  = flag(t.team?.name || '');
  const xi = (t.startXI || [])
    .sort((a,b) => (posOrder[a.player?.pos]||5) - (posOrder[b.player?.pos]||5))
    .map(p => (nameMap[p.player?.name] || p.player?.name || ''))
    .filter(Boolean).join('  ·  ');
  return [`${f} ${t.team?.name} (${t.formation||'?'})  ·  DT: ${t.coach?.name||'?'}`, xi].join('\n');
}

